(()=>{document.addEventListener("DOMContentLoaded",function(){let e=document.querySelector(".swiper");if(e){let t=new Swiper(e,{loop:!1,speed:800,autoplay:{delay:5e3,disableOnInteraction:!1,pauseOnMouseEnter:!0},navigation:{nextEl:".next",prevEl:".prev"},pagination:{el:".dots",clickable:!0,dynamicBullets:!1},effect:"fade",fadeEffect:{crossFade:!0},a11y:{enabled:!0,prevSlideMessage:"Previous slide",nextSlideMessage:"Next slide",paginationBulletMessage:"Go to slide {{index}}"}})}});})();
